import json
import os

# List available files in /tmp
files = [f for f in os.listdir('/tmp') if f.endswith('.json')]
print('Available JSON files:', files)

# Check if any contain BRCA data
for file in files:
    if 'tmp' in file:
        print('Checking', file)
        try:
            with open(f'/tmp/{file}', 'r') as f:
                data = json.load(f)
                if data and len(data) > 0:
                    print('  First record keys:', list(data[0].keys())[:5])
                    if 'Patient_description' in str(data[0]):
                        print('  Contains Patient_description')
        except:
            pass

result = {'status': 'file_check_complete'}
print('__RESULT__:')
print(json.dumps(result))

